tool.command:
mkdir out ;
## This tool requires more than the default shared memory size. You can unset this if you configure Docker to launch shm-size=128gb export CUDA_VISIBLE_DEVICES=0 ;
mv "$peaks" "$peaks.element_identifier" ;
#set $options = ""
#if $wavelengthMin: #set $options = $options + " --wavelength-min " + str($wavelengthMin) + " " #end if #if $wavelengthMax: #set $options = $options + " --wavelength-max " + str($wavelengthMax) + " " #end if #if $kiVec != "": #set $options = $options + " --ki-vec " + str($kiVec) + " " #end if #if $goniometer: mv "$goniometer" "$goniometer.element_identifier" ; #set $options = $options + " --goniometer-csv-filename " + str($goniometer.element_identifier) + " " #end if #if $nexus: mv "$nexus" "$nexus.element_identifier" ; #set $options = $options + " --nexus " + str($nexus.element_identifier) + " " #end if #if $sigmaInit: #set $options = $options + " --sigma-init " + str($sigmaInit) + " " #end if #if $freeze: #set $options = $options + " --freeze-orientation " #end if #if $goniometerAxes: #set $options = $options + " --refine-goniometer-axes " + str($goniometerAxes) + " " #end if #if $bootstrap: mv "$bootstrap" "$bootstrap.element_identifier" ; #set $options = $options + " --bootstrap " + str($bootstrap.element_identifier) + " " #end if #if $dMin: #set $options = $options + " --d-min " + str($dMin) + " " #end if #if $dMax: #set $options = $options + " --d-max " + str($dMax) + " " #end if #if $batch: #set $options = $options + " --batch-size " + str($batch) + " " #end if #if $bSharpen: #set $options = $options + " --b-sharpen " + str($bSharpen) + " " #end if #if $lattice: #set $options = $options + " --refine-lattice " #end if #if $refineGoniometer: #set $options = $options + " --refine-goniometer " #end if #if $refineSample: #set $options = $options + " --refine-sample " #end if #if $refineBeam: #set $options = $options + " --refine-beam " #end if #if $refineDetector: #set $options = $options + " --refine-detector " #end if #if $refineDetectorBanks != "": #set $options = $options + " --refine-detector-banks " + str($refineDetectorBanks) + " " #end if
python -m subhkl.io.parser indexer $peaks.element_identifier out/indexer.h5 --a $a --b $b --c $c --alpha $alpha --beta $beta --gamma $gamma --space-group $space $options --instrument $instrument --n-runs=$runs --popsize=$population --gens=$generations --strategy=$strategy --tolerance-deg=$tolerance --seed $seed --lattice-bound-frac $latticeFrac --goniometer-bound-deg $goniometerBound --sample-bound-meters $sampleBound --beam-bound-deg $beamBound --detector-modes $detectorModes --detector-trans-bound-meters $detectorTrans --detector-rot-bound-deg $detectorRot --detector-global-rot-bound-deg $detectorGlobalRot --detector-global-rot-axis $detectorAxis --detector-global-trans-bound-meters $detectorGlobalTrans --detector-radial-bound-frac $detectorRadial --num-candidates $candidates
